form:Form.form:Scripts:
		function LoadForm()
{
	CtrlEnabled("GRIDSUSP", false);
	Ctrl('e_dias_susp_real').SetXValue("0");
}

function SetSancionValues()
{			
	var sancion;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	sancion = nSQL.GetOBJ(Ctrl("main").getResource("QRY_DATOS_SANCION"), "<PARAM oi_sancion=\""+Ctrl("oi_sancion").GetXValue()+"\" />");

	Ctrl('notifica').SetXValue(sancion.l_notificacion);	
	if (Ctrl("oi_sancion").GetXValue() != "")
	{
		if (sancion.l_suspension == "true")
			{
			CtrlEnabled("GRIDSUSP", true);
			calculoDeDias();
			}	
		else
			{
			Ctrl('GRIDSUSP').DelAllRows();				
			CtrlEnabled("GRIDSUSP", false);
			calculoDeDias();
			}

		if (sancion.e_dias_suspension)
			Ctrl('e_dias_susp_prop').SetXValue(sancion.e_dias_suspension);
		else
			Ctrl('e_dias_susp_prop').SetXValue(0); 

	}
	else
	{
		Ctrl('GRIDSUSP').DelAllRows();				
		CtrlEnabled("GRIDSUSP", false);
		calculoDeDias();
		Ctrl('e_dias_susp_prop').SetXValue(0); 
	} 

}

function SetSancion()
{
	var sancion;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	sancion = nSQL.GetOBJ(Ctrl("main").getResource("QRY_SANCION"), "<PARAM oi_motivo_sancion=\""+Ctrl("oi_motivo_sancion").GetXValue()+"\" />"); 		
	if(sancion.oi_sancion != "0")
		Ctrl("oi_sancion").SetXValue(sancion.oi_sancion);				
	if(parseInt(sancion.e_cant_repeticion_leg) > parseInt(sancion.e_cant_repeticion))
		alert("El legajo ya superó la cantidad de sanciones asociadas al motivo ingresado")
}             

function ChangeSelect()
{	
	var sancion;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	sancion = nSQL.GetOBJ(Ctrl("main").getResource("QRY_DATOS_SANCION"), "<PARAM oi_sancion=\""+Ctrl("LIST").GetSelectAttrValue("id_sancion")+"\" />");
	Ctrl('notifica').SetXValue(sancion.l_notificacion);
}

function ValidateData()
{
	if(ValidarGrid() && ValidarSolapamiento())	
	{	
	var sancion;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	sancion = nSQL.GetOBJ(Ctrl("main").getResource("QRY_DATOS_SANCION"), "<PARAM oi_sancion=\""+Ctrl("oi_sancion").GetXValue()+"\" />"); 					
	if (sancion.e_dias_max_susp)
	{
		if(parseInt(Ctrl('e_dias_susp_real').GetXValue(), 10) > parseInt(sancion.e_dias_max_susp, 10))
		{
			alert('Los días de suspensión reales imputados superan el máximo permitido según lo definido en la sanción (' + sancion.e_dias_max_susp + ')');
			return false;
		}
	}
	if (Ctrl('e_dias_susp_prop').GetXValue() != "")
	{		
		if(Ctrl('e_dias_susp_real').GetXValue() != Ctrl('e_dias_susp_prop').GetXValue())
		{
			if(Ctrl('o_motivo_ajuste').GetXValue() == '')
			{
				alert('Debe especificar el motivo de ajuste de días de suspensión dado que no se respetó el valor propuesto');
				CtrlFocus('o_motivo_ajuste');
				return false;
			}
		}
	} 	
	if(Ctrl('licencia'))
	{
		if(Ctrl('licencia').GetXValue() != "1")
		{
			if (confirm("La/s licencia/s correspondiente/s a la sanción no serán generadas. ¿Desea continuar de todas maneras?"))			
				Ctrl('licvalue').SetXValue("0");							
			else
				return false;
		}
		else		
			Ctrl('licvalue').SetXValue("1");					
	}
	else	
		Ctrl('licvalue').SetXValue("0");			
	Ctrl("f_estado").SetXValue(datetime2str(new Date()));
	Ctrl('main').DoEvent("guardar");
	}
}

//Función que antes de Guardar los cambios valida que no se encuentre campos de fecha vacios en el grid
function ValidarGrid()
{
	var totdias = 0;

	for (i=0;i<Ctrl('GRIDSUSP').TotalRowsCount();i++)	
	{	
		var ctrlini = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_ini", i);
		var ctrlfin = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_fin", i);		

		if (ctrlini.GetXValue() == "" || ctrlfin.GetXValue() == "" )
		{
			alert('Las fechas de Inicio y Fin de cada suspensión son obligatorias'); 
			if(ctrlfin.GetXValue() == "")
			Ctrl('GRIDSUSP').GetCellControl('f_fechahora_fin',i).SetFocus();
			if(ctrlini.GetXValue() == "")
			Ctrl('GRIDSUSP').GetCellControl('f_fechahora_ini',i).SetFocus();	
			return false;
		}

		if (ctrlini.GetXValue() > ctrlfin.GetXValue())
		{
			alert('La fecha de inicio debe ser menor o igual a la fecha de fin');
			Ctrl('GRIDSUSP').GetCellControl('f_fechahora_fin',i).SetFocus();
			return false;
		}

	}
	return true;

}

function ChangeLic()
{   
  if(Ctrl('licencia').GetXValue()=="1")
	{
		CtrlEnabled('c_estado', false);
		Ctrl('c_estado').SetXValue('A');
	}
	else
	{
		CtrlEnabled('c_estado', true);
		Ctrl('c_estado').SetXValue('');
	}	
}

//Funcion cambio de fecha inicio
function cambioFechaIni()
{   
	validarFila();
	calculoDeDias();			
}           

//Funcion cambio de fecha fin
function cambioFechaFin()
{
	validarFila();
	calculoDeDias();
}

//Funcion que se ejecuta al eliminar una fila
function eliminaFila()
{
	calculoDeDias();
}


//Funcion para el calculo de dias de suspension de la grilla y los dias de suspension reales
function calculoDeDias(){

	var totdias = 0;    

    //Recorre la grilla                
	for (i=0;i<Ctrl('GRIDSUSP').TotalRowsCount();i++)	
	{		 

		var ctrlini = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_ini", i);
		var ctrlfin = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_fin", i);

        //Si se dan las condiciones asigna el valor a los dias de la grilla         
		if (ctrlini.GetXValue() != "" && ctrlfin.GetXValue() != "" && ctrlini.GetXValue() <= ctrlfin.GetXValue())
		{   
			var dias;
			dias = ((str2datetime(ctrlfin.GetXValue()) - str2datetime(ctrlini.GetXValue()))/(1000*60*60*24))+1;
			totdias = totdias + dias;			
			Ctrl('GRIDSUSP').SetCellXValue("e_dias_susp", i, parseInt(dias).toString())
		}   

		else
		{
			Ctrl('GRIDSUSP').SetCellXValue("e_dias_susp", i, "");
		}		    

	}

	//Completa los dias de suspension real
	if(totdias==0)
	Ctrl('e_dias_susp_real').SetXValue("0");
	else
	Ctrl('e_dias_susp_real').SetXValue(parseInt(totdias).toString());

}

//Funcion para validar fila seleccionada
function validarFila()
{
	var id=Ctrl('GRIDSUSP').GetSelectedRowIdx();  

	var ctrlini = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_ini", id);
	var ctrlfin = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_fin", id);

	if (ctrlini.GetXValue() != "" && ctrlfin.GetXValue() != "" && ctrlini.GetXValue() > ctrlfin.GetXValue() )
		{
		alert('La fecha de inicio debe ser menor o igual a la fecha de fin');
		return false;
		}

}

//Valida que no se solapen las fechas de la grilla
function ValidarSolapamiento()
{

	for (i=0;i<Ctrl('GRIDSUSP').TotalRowsCount();i++)
	{   
		var fechaDesde = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_ini", i).GetXValue();
		var fechaHasta = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_fin", i).GetXValue();

		for(j=i+1; j<Ctrl('GRIDSUSP').TotalRowsCount();j++)
		{  
			var fi = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_ini", j).GetXValue();
			var ff = Ctrl('GRIDSUSP').GetCellControl("f_fechahora_fin", j).GetXValue();

		   	if (fechaDesde > ff) 
		   	{
		   	continue;
		   	}
            if (fechaHasta < fi) 
            {
            continue;
            }
            alert('Las fechas de suspensiones en la grilla no se pueden superponer.'); 
            return false;
		}

	}

	return true;

}
